import { MOCK_TRANSACTIONS } from './constants';
import Dashboard from './components/Dashboard';
import Activity from './components/Activity';
import Pay from './components/Pay';
import Insights from './components/Insights';
import Profile from './components/Profile';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<ViewType>('home');
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS);
  const [balance, setBalance] = useState(5420.75);

  const handleTransaction = (newTx: Transaction) => {
    setTransactions([newTx, ...transactions]);
    if (newTx.type === 'debit') {
      setBalance(prev => prev - newTx.amount);
    } else {
      setBalance(prev => prev + newTx.amount);
    }
    setActiveView('home');
  };

  const renderView = () => {
    switch (activeView) {
      case 'home':
        return <Dashboard balance={balance} transactions={transactions} onNavigate={setActiveView} />;
      case 'activity':
        return <Activity transactions={transactions} />;
      case 'pay':
        return <Pay onComplete={handleTransaction} onCancel={() => setActiveView('home')} />;
      case 'insights':
        return <Insights transactions={transactions} />;
      case 'profile':
        return <Profile />;
      default:
        return <Dashboard balance={balance} transactions={transactions} onNavigate={setActiveView} />;
    }
  };

  return (
    <div className="max-w-md mx-auto min-h-screen bg-white shadow-xl relative pb-20 overflow-hidden flex flex-col">
      {/* Header */}
      <header className="px-6 py-4 flex items-center justify-between bg-white sticky top-0 z-10 border-b border-gray-100">
