            GP
          </div>
          <span className="text-xl font-medium text-gray-700">Pay</span>
        </div>
        <div className="flex items-center gap-4">
          <button className="text-gray-500 hover:text-gray-800 transition-colors">
            <Bell size={24} />
          </button>
          <button 
            onClick={() => setActiveView('profile')}
            className="w-9 h-9 rounded-full overflow-hidden border-2 border-transparent hover:border-blue-500 transition-all"
          >
            <img src="https://picsum.photos/100/100?random=10" alt="Profile" className="w-full h-full object-cover" />
          </button>
        </div>
      </header>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto custom-scrollbar">
        {renderView()}
      </main>

      {/* Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 max-w-md mx-auto bg-white border-t border-gray-200 flex justify-around items-center py-2 px-4 z-20">
